#include "hirct/Target/GenDPIC.h"
#include "hirct/Analysis/IRAnalysis.h"

#include <cctype>
#include <cerrno>
#include <cstring>
#include <fstream>
#include <iostream>
#include <sys/stat.h>

namespace hirct {

static constexpr const char *AUTO_GENERATED_HEADER =
    "// AUTO-GENERATED by hirct-gen \xe2\x80\x94 DO NOT EDIT\n";

static std::string to_lower(const std::string &s) {
  std::string r;
  r.reserve(s.size());
  for (char c : s)
    r += static_cast<char>(tolower(static_cast<unsigned char>(c)));
  return r;
}

static bool ends_with(const std::string &s, const std::string &suffix) {
  return s.size() >= suffix.size() &&
         s.compare(s.size() - suffix.size(), suffix.size(), suffix) == 0;
}

static bool starts_with(const std::string &s, const std::string &prefix) {
  return s.size() >= prefix.size() && s.compare(0, prefix.size(), prefix) == 0;
}

GenDPIC::GenDPIC(circt::hw::HWModuleOp hw_module, mlir::ModuleOp mlir_module)
    : hw_module_(hw_module),
      mlir_module_(mlir_module),
      module_name_(hw_module.getSymName().str()) {
  cdm_view_ = hirct::build_clock_domain_map(hw_module_, mlir_module_);
}

std::string GenDPIC::dpi_c_type_for_width(int width) const {
  if (width == 1)
    return "svBit";
  if (width <= 32)
    return "int";
  if (width <= 64)
    return "long long";
  return "";
}

std::string GenDPIC::sv_dpi_type_for_width(int width) const {
  if (width == 1)
    return "bit";
  if (width <= 32)
    return "int";
  if (width <= 64)
    return "longint";
  return "";
}

std::string GenDPIC::func_prefix() const {
  return to_lower(module_name_);
}

// ---------------------------------------------------------------------------
// emit — top-level entry point
// ---------------------------------------------------------------------------

bool GenDPIC::emit(const std::string &output_dir) {
  std::string dpi_dir = output_dir + "/dpi";
  if (mkdir(dpi_dir.c_str(), 0755) != 0 && errno != EEXIST) {
    std::cerr << "GenDPIC: cannot create directory: " << dpi_dir << ": "
              << strerror(errno) << "\n";
    return false;
  }

  if (!emit_header(dpi_dir))
    return false;
  if (!emit_impl(dpi_dir))
    return false;
  if (!emit_sv(dpi_dir))
    return false;
  return true;
}

std::vector<ClockResetPair> GenDPIC::build_clock_reset_pairs() const {
  std::vector<ClockResetPair> pairs;
  std::vector<std::string> used_resets;

  auto ports_vec = hirct::get_ports(hw_module_);

  for (const auto &domain : cdm_view_.domains) {
    ClockResetPair pair;
    pair.clock_name = domain.clock_port_name;

    std::string clk_lower = to_lower(domain.clock_port_name);
    std::string clk_prefix;
    if (clk_lower == "pclk" || starts_with(clk_lower, "pclk_"))
      clk_prefix = "p";
    else if (clk_lower == "sclk" || starts_with(clk_lower, "sclk_"))
      clk_prefix = "s";
    else if (ends_with(clk_lower, "_clk"))
      clk_prefix = clk_lower.substr(0, clk_lower.size() - 4);
    else if (ends_with(clk_lower, "_pclk"))
      clk_prefix = clk_lower.substr(0, clk_lower.size() - 5);

    for (const auto &p : ports_vec) {
      if (!hirct::is_reset_port(p.name))
        continue;
      std::string rst_lower = to_lower(p.name);
      if (!clk_prefix.empty() &&
          (rst_lower.find(clk_prefix + "reset") != std::string::npos ||
           rst_lower.find(clk_prefix + "rst") != std::string::npos)) {
        pair.reset_name = p.name;
        pair.active_low = hirct::is_active_low_reset(p.name);
        break;
      }
    }

    if (pair.reset_name.empty()) {
      for (const auto &p : ports_vec) {
        if (!hirct::is_reset_port(p.name))
          continue;
        bool already_used = false;
        for (const auto &u : used_resets) {
          if (u == p.name) {
            already_used = true;
            break;
          }
        }
        if (!already_used) {
          pair.reset_name = p.name;
          pair.active_low = hirct::is_active_low_reset(p.name);
          break;
        }
      }
    }

    if (!pair.reset_name.empty())
      used_resets.push_back(pair.reset_name);
    pairs.push_back(std::move(pair));
  }
  return pairs;
}

// ---------------------------------------------------------------------------
// emit_header — generates <ModuleName>_dpi.h
// ---------------------------------------------------------------------------

bool GenDPIC::emit_header(const std::string &dir) {
  std::string name = module_name_;
  std::string prefix = func_prefix();
  std::string path = dir + "/" + name + "_dpi.h";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenDPIC: cannot open " << path << "\n";
    return false;
  }

  std::string guard = name + "_DPI_H";
  for (auto &c : guard)
    c = static_cast<char>(toupper(static_cast<unsigned char>(c)));

  ofs << AUTO_GENERATED_HEADER;
  ofs << "#ifndef " << guard << "\n";
  ofs << "#define " << guard << "\n\n";

  ofs << "#if __has_include(\"svdpi.h\")\n";
  ofs << "#include \"svdpi.h\"\n";
  ofs << "#else\n";
  ofs << "typedef unsigned char svBit;\n";
  ofs << "#endif\n\n";

  ofs << "#ifdef __cplusplus\n";
  ofs << "extern \"C\" {\n";
  ofs << "#endif\n\n";

  ofs << "void *" << prefix << "_create();\n";
  ofs << "void " << prefix << "_destroy(void *handle);\n";
  ofs << "void " << prefix << "_do_reset(void *handle);\n";
  ofs << "void " << prefix << "_step(void *handle);\n";
  ofs << "void " << prefix << "_eval_comb(void *handle);\n";

  bool is_multi = cdm_view_.is_multi_clock;
  if (is_multi) {
    for (const auto &d : cdm_view_.domains) {
      ofs << "void " << prefix << "_step_" << to_lower(d.clock_port_name)
          << "(void *handle);\n";
    }
  }

  auto ports = hirct::get_ports(hw_module_);
  for (const auto &p : ports) {
    bool is_clock = hirct::is_clock_port(p.name);
    if (is_clock)
      continue;
    std::string ctype = dpi_c_type_for_width(static_cast<int>(p.width));
    if (ctype.empty()) {
      std::cerr << "GenDPIC: unsupported width " << p.width << " for port "
                << p.name << "\n";
      return false;
    }
    if (p.is_input) {
      ofs << "void " << prefix << "_set_" << p.name << "(void *handle, "
          << ctype << " value);\n";
    } else {
      ofs << ctype << " " << prefix << "_get_" << p.name << "(void *handle);\n";
    }
  }

  ofs << "\n#ifdef __cplusplus\n";
  ofs << "}\n";
  ofs << "#endif\n\n";
  ofs << "#endif // " << guard << "\n";
  return true;
}

// ---------------------------------------------------------------------------
// emit_impl — generates <ModuleName>_dpi.cpp
// ---------------------------------------------------------------------------

bool GenDPIC::emit_impl(const std::string &dir) {
  std::string name = module_name_;
  std::string prefix = func_prefix();
  std::string path = dir + "/" + name + "_dpi.cpp";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenDPIC: cannot open " << path << "\n";
    return false;
  }

  ofs << AUTO_GENERATED_HEADER;
  ofs << "#include \"" << name << "_dpi.h\"\n";
  ofs << "#include \"../cmodel/" << name << ".h\"\n\n";
  ofs << "extern \"C\" {\n\n";

  ofs << "void *" << prefix << "_create() { return new " << name << "(); }\n\n";

  ofs << "void " << prefix << "_destroy(void *handle) {\n";
  ofs << "  delete static_cast<" << name << " *>(handle);\n";
  ofs << "}\n\n";

  ofs << "void " << prefix << "_do_reset(void *handle) {\n";
  ofs << "  static_cast<" << name << " *>(handle)->do_reset();\n";
  ofs << "}\n\n";

  ofs << "void " << prefix << "_step(void *handle) {\n";
  ofs << "  static_cast<" << name << " *>(handle)->step();\n";
  ofs << "}\n\n";

  ofs << "void " << prefix << "_eval_comb(void *handle) {\n";
  ofs << "  static_cast<" << name << " *>(handle)->eval_comb();\n";
  ofs << "}\n\n";

  bool is_multi = cdm_view_.is_multi_clock;
  if (is_multi) {
    for (const auto &d : cdm_view_.domains) {
      std::string lower_domain = to_lower(d.clock_port_name);
      ofs << "void " << prefix << "_step_" << lower_domain
          << "(void *handle) {\n";
      ofs << "  static_cast<" << name << " *>(handle)->step_"
          << lower_domain << "();\n";
      ofs << "}\n\n";
    }
  }

  auto ports = hirct::get_ports(hw_module_);
  for (const auto &p : ports) {
    bool is_clock = hirct::is_clock_port(p.name);
    if (is_clock)
      continue;
    std::string ctype = dpi_c_type_for_width(static_cast<int>(p.width));
    if (ctype.empty()) {
      std::cerr << "GenDPIC: unsupported width " << p.width << " for port "
                << p.name << "\n";
      return false;
    }
    if (p.is_input) {
      ofs << "void " << prefix << "_set_" << p.name << "(void *handle, "
          << ctype << " value) {\n";
      ofs << "  static_cast<" << name << " *>(handle)->" << p.name
          << " = value;\n";
      ofs << "}\n\n";
    } else {
      ofs << ctype << " " << prefix << "_get_" << p.name
          << "(void *handle) {\n";
      ofs << "  return static_cast<" << name << " *>(handle)->" << p.name
          << ";\n";
      ofs << "}\n\n";
    }
  }

  ofs << "} // extern \"C\"\n";
  return true;
}

// ---------------------------------------------------------------------------
// emit_sv — generates <ModuleName>_dpi.sv
// ---------------------------------------------------------------------------

bool GenDPIC::emit_sv(const std::string &dir) {
  std::string name = module_name_;
  std::string prefix = func_prefix();
  std::string path = dir + "/" + name + "_dpi.sv";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenDPIC: cannot open " << path << "\n";
    return false;
  }

  auto ports = hirct::get_ports(hw_module_);
  auto input_ports = hirct::get_input_ports(hw_module_);
  auto output_ports = hirct::get_output_ports(hw_module_);

  // cdm_view_.domains[0]이 primary clock (reg_count 내림차순 정렬됨)
  // is_clock_port() 이름 휴리스틱 대신 IR 분석 결과를 사용한다
  std::string clock_name;
  std::string reset_name;
  bool active_low = false;
  if (!cdm_view_.domains.empty())
    clock_name = cdm_view_.domains[0].clock_port_name;

  if (!clock_name.empty()) {
    std::string clk_lower = to_lower(clock_name);
    std::string clk_prefix;
    if (clk_lower == "pclk" || ends_with(clk_lower, "_pclk") ||
        starts_with(clk_lower, "pclk_"))
      clk_prefix = "p";
    else if (ends_with(clk_lower, "_clk"))
      clk_prefix = clk_lower.substr(0, clk_lower.size() - 4);

    // primary clock prefix와 대응하는 reset 우선 선택
    for (const auto &p : ports) {
      if (!hirct::is_reset_port(p.name))
        continue;
      std::string rst_lower = to_lower(p.name);
      if (!clk_prefix.empty() &&
          (rst_lower.find(clk_prefix + "reset") != std::string::npos ||
           rst_lower.find(clk_prefix + "rst") != std::string::npos ||
           rst_lower.find(clk_prefix + "preset") != std::string::npos)) {
        reset_name = p.name;
        active_low = hirct::is_active_low_reset(p.name);
        break;
      }
    }
    // fallback: prefix 매칭 없으면 첫 번째 reset
    if (reset_name.empty()) {
      for (const auto &p : ports) {
        if (hirct::is_reset_port(p.name)) {
          reset_name = p.name;
          active_low = hirct::is_active_low_reset(p.name);
          break;
        }
      }
    }
  }

  ofs << AUTO_GENERATED_HEADER;
  ofs << "module " << name << "_dpi_wrapper(\n";

  bool first = true;
  for (const auto &p : ports) {
    if (!first)
      ofs << ",\n";
    first = false;
    std::string dir_kw = p.is_input ? "input " : "output";
    if (p.width == 1) {
      ofs << "  " << dir_kw << " logic        " << p.name;
    } else {
      ofs << "  " << dir_kw << " logic [" << (p.width - 1) << ":0] " << p.name;
    }
  }
  ofs << "\n);\n\n";

  ofs << "  import \"DPI-C\" function chandle " << prefix << "_create();\n";
  ofs << "  import \"DPI-C\" function void " << prefix
      << "_destroy(chandle handle);\n";
  ofs << "  import \"DPI-C\" function void " << prefix
      << "_do_reset(chandle handle);\n";
  ofs << "  import \"DPI-C\" function void " << prefix
      << "_step(chandle handle);\n";
  ofs << "  import \"DPI-C\" function void " << prefix
      << "_eval_comb(chandle handle);\n";

  bool is_multi = cdm_view_.is_multi_clock;
  if (is_multi) {
    for (const auto &d : cdm_view_.domains) {
      ofs << "  import \"DPI-C\" function void " << prefix << "_step_"
          << to_lower(d.clock_port_name) << "(chandle handle);\n";
    }
  }

  for (const auto &p : ports) {
    bool is_clock = hirct::is_clock_port(p.name);
    if (is_clock)
      continue;
    std::string svtype = sv_dpi_type_for_width(static_cast<int>(p.width));
    if (svtype.empty()) {
      std::cerr << "GenDPIC: unsupported width " << p.width << " for port "
                << p.name << "\n";
      return false;
    }
    if (p.is_input) {
      ofs << "  import \"DPI-C\" function void " << prefix << "_set_" << p.name
          << "(chandle handle, " << svtype << " value);\n";
    } else {
      ofs << "  import \"DPI-C\" function " << svtype << " " << prefix
          << "_get_" << p.name << "(chandle handle);\n";
    }
  }
  ofs << "\n";

  ofs << "  chandle model_handle;\n\n";
  ofs << "  initial model_handle = " << prefix << "_create();\n";
  ofs << "  final " << prefix << "_destroy(model_handle);\n\n";

  if (is_multi) {
    auto pairs = build_clock_reset_pairs();
    bool is_primary = true;
    for (const auto &crp : pairs) {
      std::string lower_domain = to_lower(crp.clock_name);
      ofs << "  always @(posedge " << crp.clock_name << ") begin\n";

      if (!crp.reset_name.empty() && is_primary) {
        if (crp.active_low)
          ofs << "    if (!" << crp.reset_name << ") begin\n";
        else
          ofs << "    if (" << crp.reset_name << ") begin\n";
        ofs << "      " << prefix << "_do_reset(model_handle);\n";
        ofs << "    end else begin\n";

        for (const auto &p : input_ports) {
          if (hirct::is_clock_port(p.name))
            continue;
          ofs << "      " << prefix << "_set_" << p.name << "(model_handle, "
              << p.name << ");\n";
        }
        ofs << "      " << prefix << "_step_" << lower_domain
            << "(model_handle);\n";
        for (const auto &p : output_ports) {
          ofs << "      " << p.name << " = " << prefix << "_get_" << p.name
              << "(model_handle);\n";
        }
        ofs << "    end\n";
      } else if (!crp.reset_name.empty()) {
        if (crp.active_low)
          ofs << "    if (" << crp.reset_name << ") begin\n";
        else
          ofs << "    if (!" << crp.reset_name << ") begin\n";

        for (const auto &p : input_ports) {
          if (hirct::is_clock_port(p.name))
            continue;
          ofs << "      " << prefix << "_set_" << p.name << "(model_handle, "
              << p.name << ");\n";
        }
        ofs << "      " << prefix << "_step_" << lower_domain
            << "(model_handle);\n";
        for (const auto &p : output_ports) {
          ofs << "      " << p.name << " = " << prefix << "_get_" << p.name
              << "(model_handle);\n";
        }
        ofs << "    end\n";
      } else {
        for (const auto &p : input_ports) {
          if (hirct::is_clock_port(p.name))
            continue;
          ofs << "    " << prefix << "_set_" << p.name << "(model_handle, "
              << p.name << ");\n";
        }
        ofs << "    " << prefix << "_step_" << lower_domain
            << "(model_handle);\n";
        for (const auto &p : output_ports) {
          ofs << "    " << p.name << " = " << prefix << "_get_" << p.name
              << "(model_handle);\n";
        }
      }
      ofs << "  end\n\n";
      is_primary = false;
    }
  } else if (!clock_name.empty()) {
    ofs << "  always @(posedge " << clock_name << ") begin\n";
    if (!reset_name.empty()) {
      if (active_low)
        ofs << "    if (!" << reset_name << ") begin\n";
      else
        ofs << "    if (" << reset_name << ") begin\n";
      ofs << "      " << prefix << "_do_reset(model_handle);\n";
      ofs << "    end else begin\n";

      for (const auto &p : input_ports) {
        if (hirct::is_clock_port(p.name))
          continue;
        ofs << "      " << prefix << "_set_" << p.name << "(model_handle, "
            << p.name << ");\n";
      }
      ofs << "      " << prefix << "_step(model_handle);\n";
      for (const auto &p : output_ports) {
        ofs << "      " << p.name << " = " << prefix << "_get_" << p.name
            << "(model_handle);\n";
      }

      ofs << "    end\n";
    } else {
      for (const auto &p : input_ports) {
        if (hirct::is_clock_port(p.name))
          continue;
        ofs << "    " << prefix << "_set_" << p.name << "(model_handle, "
            << p.name << ");\n";
      }
      ofs << "    " << prefix << "_step(model_handle);\n";
      for (const auto &p : output_ports) {
        ofs << "    " << p.name << " = " << prefix << "_get_" << p.name
            << "(model_handle);\n";
      }
    }
    ofs << "  end\n\n";
  } else {
    ofs << "  always @(*) begin\n";
    for (const auto &p : input_ports) {
      if (hirct::is_clock_port(p.name))
        continue;
      ofs << "    " << prefix << "_set_" << p.name << "(model_handle, "
          << p.name << ");\n";
    }
    ofs << "    " << prefix << "_eval_comb(model_handle);\n";
    for (const auto &p : output_ports) {
      ofs << "    " << p.name << " = " << prefix << "_get_" << p.name
          << "(model_handle);\n";
    }
    ofs << "  end\n\n";
  }

  ofs << "endmodule\n";
  return true;
}

} // namespace hirct
